+import { DynamoDBToolboxError } from '~/errors/index.js'
+import type { ItemSchema, MapSchema } from '~/schema/index.js'
+import { formatArrayPath } from '~/schema/actions/utils/formatArrayPath.js'
+
+type ObjectSchema = ItemSchema | MapSchema
+
+/** Validate sibling-dependent requirements after defaults and links have been applied. */
+export const validateRequiredIf = (
+  schema: ObjectSchema,
+  value: Record<string, unknown>,
+  valuePath: (string | number)[] = []
+): void => {
+  for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+    if (attribute.props.required === 'always' || value[attributeName] !== undefined) continue
+
+    for (const requirement of attribute.props.requiredIf ?? []) {
+      const controllingValue = value[requirement.attributeName]
+      if (controllingValue !== undefined && requirement.values.some(v => Object.is(v, controllingValue))) {
+        const path = formatArrayPath([...valuePath, attributeName])
+        throw new DynamoDBToolboxError('parsing.attributeRequired', {
+          message: `Attribute '${path}' is required when '${formatArrayPath([
+            ...valuePath,
+            requirement.attributeName
+          ])}' matches a requiredIf value.`,
+          path
+        })
+      }
+    }
+  }
+}
